import { useEffect, useRef, useState, useCallback } from 'react';

const HOTSPOTS = [
  { id: 'neck',    label: 'Cervical Spine', sub: 'C1–C7 Vertebrae',  cx: 230, cy: 118 },
  { id: 'shoulder',label: 'Shoulder Joint',  sub: 'Rotator Cuff',      cx: 130, cy: 178 },
  { id: 'lumbar',  label: 'Lumbar Spine',   sub: 'L1–L5 Vertebrae',  cx: 230, cy: 345 },
  { id: 'knee',    label: 'Knee Joint',      sub: 'Patella & Meniscus',cx: 195, cy: 560 },
];

/* ─────────────────────────────────────────
   SKELETON SVG  (viewBox 0 0 460 820)
───────────────────────────────────────── */
const SkeletonSVG = ({ scanY, hovered, setHovered }) => (
  <svg viewBox="0 0 460 820" width="380" height="660"
    xmlns="http://www.w3.org/2000/svg"
    style={{ display:'block', overflow:'visible',
      filter:'drop-shadow(0 0 18px rgba(219,38,29,0.6)) drop-shadow(0 0 50px rgba(140,0,0,0.3))' }}>
    <defs>
      {/* Bone surface gradient */}
      <radialGradient id="bone" cx="35%" cy="25%" r="70%">
        <stop offset="0%"  stopColor="#ffb088"/>
        <stop offset="45%" stopColor="#c94422"/>
        <stop offset="100%" stopColor="#7a1008"/>
      </radialGradient>
      <radialGradient id="boneFlat" cx="50%" cy="30%" r="65%">
        <stop offset="0%"  stopColor="#f08060"/>
        <stop offset="60%" stopColor="#aa2810"/>
        <stop offset="100%" stopColor="#6a0a04"/>
      </radialGradient>
      <radialGradient id="boneShine" cx="30%" cy="20%" r="55%">
        <stop offset="0%"  stopColor="rgba(255,210,190,0.45)"/>
        <stop offset="100%" stopColor="rgba(100,0,0,0)"/>
      </radialGradient>
      <linearGradient id="boneL" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%"  stopColor="#d05030"/>
        <stop offset="100%" stopColor="#801010"/>
      </linearGradient>
      <radialGradient id="cavity" cx="50%" cy="50%" r="50%">
        <stop offset="0%"  stopColor="#1a0000"/>
        <stop offset="100%" stopColor="#3a0808"/>
      </radialGradient>
      <radialGradient id="pain" cx="50%" cy="50%" r="50%">
        <stop offset="0%"  stopColor="#ffffff"/>
        <stop offset="20%" stopColor="#ffe066"/>
        <stop offset="55%" stopColor="#ff4400" stopOpacity="0.9"/>
        <stop offset="100%" stopColor="#cc0000" stopOpacity="0"/>
      </radialGradient>
      <linearGradient id="scan" x1="0%" y1="0%" x2="0%" y2="100%">
        <stop offset="0%"  stopColor="rgba(255,80,40,0)"/>
        <stop offset="50%" stopColor="rgba(255,100,60,0.65)"/>
        <stop offset="100%" stopColor="rgba(255,80,40,0)"/>
      </linearGradient>
      <filter id="g1"><feGaussianBlur stdDeviation="1.8" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
      <filter id="g2"><feGaussianBlur stdDeviation="3.5" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
      <filter id="g3"><feGaussianBlur stdDeviation="6" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
      <clipPath id="bodyClip"><rect x="50" y="0" width="360" height="820"/></clipPath>
    </defs>

    {/* ═══════════════════════════════════════
        SKULL
    ═══════════════════════════════════════ */}
    {/* Cranium dome */}
    <ellipse cx="230" cy="55" rx="58" ry="54" fill="url(#bone)" stroke="#db261d" strokeWidth="1.4" filter="url(#g1)"/>
    <ellipse cx="230" cy="55" rx="58" ry="54" fill="url(#boneShine)"/>
    {/* Parietal ridges */}
    <path d="M174 40 Q170 55 176 72" fill="none" stroke="rgba(219,38,29,0.35)" strokeWidth="2"/>
    <path d="M286 40 Q290 55 284 72" fill="none" stroke="rgba(219,38,29,0.35)" strokeWidth="2"/>
    {/* Temporal bone detail */}
    <path d="M173 68 Q160 75 164 90 Q170 96 180 92" fill="url(#boneFlat)" stroke="#db261d" strokeWidth="1.1" filter="url(#g1)"/>
    <path d="M287 68 Q300 75 296 90 Q290 96 280 92" fill="url(#boneFlat)" stroke="#db261d" strokeWidth="1.1" filter="url(#g1)"/>
    {/* Zygomatic arch */}
    <path d="M178 86 Q160 90 162 104 Q166 110 178 108" fill="none" stroke="#db261d" strokeWidth="3" strokeLinecap="round" filter="url(#g1)"/>
    <path d="M282 86 Q300 90 298 104 Q294 110 282 108" fill="none" stroke="#db261d" strokeWidth="3" strokeLinecap="round" filter="url(#g1)"/>
    {/* Upper face / frontal bone */}
    <path d="M174 72 Q178 85 195 90 Q215 95 230 94 Q245 95 265 90 Q282 85 286 72"
      fill="url(#bone)" stroke="#db261d" strokeWidth="1.2" filter="url(#g1)"/>
    {/* Orbital (eye) sockets */}
    <ellipse cx="207" cy="76" rx="20" ry="15" fill="url(#cavity)" stroke="#db261d" strokeWidth="1.3" filter="url(#g1)"/>
    <ellipse cx="253" cy="76" rx="20" ry="15" fill="url(#cavity)" stroke="#db261d" strokeWidth="1.3" filter="url(#g1)"/>
    {/* Orbital ridges */}
    <path d="M187 65 Q207 58 227 65" fill="none" stroke="rgba(219,38,29,0.6)" strokeWidth="2" strokeLinecap="round"/>
    <path d="M233 65 Q253 58 273 65" fill="none" stroke="rgba(219,38,29,0.6)" strokeWidth="2" strokeLinecap="round"/>
    {/* Nasal bones */}
    <path d="M221 90 L218 108 Q224 112 230 112 Q236 112 242 108 L239 90 Z"
      fill="url(#boneFlat)" stroke="#db261d" strokeWidth="1" filter="url(#g1)"/>
    {/* Nasal cavity */}
    <ellipse cx="225" cy="104" rx="8" ry="7" fill="url(#cavity)" stroke="#db261d" strokeWidth="0.8"/>
    <ellipse cx="235" cy="104" rx="8" ry="7" fill="url(#cavity)" stroke="#db261d" strokeWidth="0.8"/>
    {/* Vomer (nasal septum) */}
    <line x1="230" y1="90" x2="230" y2="112" stroke="rgba(219,38,29,0.5)" strokeWidth="1.5"/>
    {/* Mandible */}
    <path d="M180 100 Q172 115 175 135 Q182 155 230 160 Q278 155 285 135 Q288 115 280 100 Q265 88 230 88 Q195 88 180 100Z"
      fill="url(#bone)" stroke="#db261d" strokeWidth="1.4" filter="url(#g1)"/>
    <path d="M180 100 Q172 115 175 135 Q182 155 230 160 Q278 155 285 135 Q288 115 280 100 Q265 88 230 88 Q195 88 180 100Z"
      fill="url(#boneShine)"/>
    {/* Mental foramen */}
    <circle cx="205" cy="138" r="3.5" fill="url(#cavity)" stroke="rgba(219,38,29,0.4)" strokeWidth="0.8"/>
    <circle cx="255" cy="138" r="3.5" fill="url(#cavity)" stroke="rgba(219,38,29,0.4)" strokeWidth="0.8"/>
    {/* Teeth */}
    {[-28,-20,-12,-4,4,12,20,28].map((dx,i)=>(
      <rect key={i} x={230+dx-4} y="148" width="7" height="9" rx="2.5"
        fill="rgba(255,230,210,0.75)" stroke="rgba(219,38,29,0.35)" strokeWidth="0.6"/>
    ))}
    {/* Mandible body */}
    <path d="M178 130 Q175 152 200 162 Q230 168 260 162 Q285 152 282 130"
      fill="none" stroke="#db261d" strokeWidth="1" strokeDasharray="3 2" opacity="0.5"/>

    {/* ═══════════════════════════════════════
        CERVICAL VERTEBRAE  C1–C7
    ═══════════════════════════════════════ */}
    {[168,180,192,204,216,228,240].map((y,i)=>(
      <g key={i}>
        {/* body */}
        <rect x={220} y={y-6} width={20} height={11} rx={3}
          fill="url(#bone)" stroke="#db261d" strokeWidth={1} filter="url(#g1)"/>
        {/* transverse processes */}
        <path d={`M220 ${y} Q208 ${y-3} 202 ${y}`} fill="none" stroke="#db261d" strokeWidth={3} strokeLinecap="round" filter="url(#g1)"/>
        <path d={`M220 ${y} Q208 ${y-3} 202 ${y}`} fill="none" stroke="url(#bone)" strokeWidth={2} strokeLinecap="round"/>
        <path d={`M240 ${y} Q252 ${y-3} 258 ${y}`} fill="none" stroke="#db261d" strokeWidth={3} strokeLinecap="round" filter="url(#g1)"/>
        <path d={`M240 ${y} Q252 ${y-3} 258 ${y}`} fill="none" stroke="url(#bone)" strokeWidth={2} strokeLinecap="round"/>
        {/* spinous process */}
        {i>0 && <ellipse cx={230} cy={y-9} rx={5} ry={4} fill="url(#boneFlat)" stroke="#db261d" strokeWidth={0.7}/>}
      </g>
    ))}

    {/* ═══════════════════════════════════════
        CLAVICLES
    ═══════════════════════════════════════ */}
    <path d="M222 168 Q196 170 168 182 Q152 190 140 200"
      stroke="#db261d" strokeWidth="9" strokeLinecap="round" fill="none" filter="url(#g1)"/>
    <path d="M222 168 Q196 170 168 182 Q152 190 140 200"
      stroke="url(#bone)" strokeWidth="7" strokeLinecap="round" fill="none"/>
    <path d="M238 168 Q264 170 292 182 Q308 190 320 200"
      stroke="#db261d" strokeWidth="9" strokeLinecap="round" fill="none" filter="url(#g1)"/>
    <path d="M238 168 Q264 170 292 182 Q308 190 320 200"
      stroke="url(#bone)" strokeWidth="7" strokeLinecap="round" fill="none"/>

    {/* ═══════════════════════════════════════
        SCAPULAE
    ═══════════════════════════════════════ */}
    <path d="M108 200 L98 256 L150 272 L168 210 Q155 195 140 198 Z"
      fill="url(#boneFlat)" stroke="#db261d" strokeWidth="1.3" filter="url(#g1)" opacity="0.75"/>
    <path d="M108 200 L98 256 L150 272 L168 210 Q155 195 140 198 Z" fill="url(#boneShine)" opacity="0.75"/>
    {/* spine of scapula */}
    <path d="M110 214 L155 208" stroke="#db261d" strokeWidth="4" strokeLinecap="round" filter="url(#g1)" opacity="0.75"/>
    <path d="M352 200 L362 256 L310 272 L292 210 Q305 195 320 198 Z"
      fill="url(#boneFlat)" stroke="#db261d" strokeWidth="1.3" filter="url(#g1)" opacity="0.75"/>
    <path d="M352 200 L362 256 L310 272 L292 210 Q305 195 320 198 Z" fill="url(#boneShine)" opacity="0.75"/>
    <path d="M350 214 L305 208" stroke="#db261d" strokeWidth="4" strokeLinecap="round" filter="url(#g1)" opacity="0.75"/>

    {/* ═══════════════════════════════════════
        STERNUM
    ═══════════════════════════════════════ */}
    {/* Manubrium */}
    <path d="M215 172 Q220 168 230 167 Q240 168 245 172 L247 192 Q230 196 213 192 Z"
      fill="url(#bone)" stroke="#db261d" strokeWidth="1.3" filter="url(#g1)"/>
    {/* Body */}
    <path d="M213 192 Q230 196 247 192 L248 290 Q230 295 212 290 Z"
      fill="url(#bone)" stroke="#db261d" strokeWidth="1.3" filter="url(#g1)"/>
    <path d="M213 192 Q230 196 247 192 L248 290 Q230 295 212 290 Z" fill="url(#boneShine)"/>
    {/* Xiphoid process */}
    <path d="M220 290 Q230 295 240 290 L235 310 L230 315 L225 310 Z"
      fill="url(#boneFlat)" stroke="#db261d" strokeWidth="1"/>
    {/* Sternal angle */}
    <line x1="213" y1="196" x2="247" y2="196" stroke="rgba(219,38,29,0.5)" strokeWidth="1.5"/>

    {/* ═══════════════════════════════════════
        RIB CAGE — 12 pairs
        (curved ribs with costal cartilage)
    ═══════════════════════════════════════ */}
    {[
      /* [sternY, L_cpx, L_cpy, L_ex, L_ey,  R_cpx, R_cpy, R_ex, R_ey, cartL, sw] */
      [200, 192,196, 128,214,  268,196, 332,214, false, 3.8],
      [212, 191,208, 120,232,  269,208, 340,232, false, 3.5],
      [224, 190,220, 114,250,  270,220, 346,250, false, 3.2],
      [236, 190,232, 110,267,  270,232, 350,267, false, 3.0],
      [248, 190,244, 108,284,  270,244, 352,284, false, 2.8],
      [260, 190,256, 108,300,  270,256, 352,300, false, 2.7],
      [270, 190,266, 110,314,  270,266, 350,314, false, 2.6],
      [278, 190,274, 115,326,  270,274, 345,326, true,  2.5],
      [284, 190,280, 122,334,  270,280, 338,334, true,  2.3],
      [288, 190,284, 135,340,  270,284, 325,340, true,  2.2],
      [0,   0,0,     148,342,  0,0,     312,342, false, 2.0], // floating
      [0,   0,0,     155,348,  0,0,     305,348, false, 1.8], // floating
    ].map(([sy,lcpx,lcpy,lx,ly, rcpx,rcpy,rx2,ry2, costal, sw],i)=>{
      const vAttach = 248 + i * 5;
      return (
        <g key={i}>
          {/* Left rib */}
          {sy > 0 ? (
            <>
              <path d={`M213 ${sy} Q${lcpx} ${lcpy} ${lx} ${ly}`}
                stroke="#db261d" strokeWidth={sw+1} strokeLinecap="round" fill="none" filter="url(#g1)"/>
              <path d={`M213 ${sy} Q${lcpx} ${lcpy} ${lx} ${ly}`}
                stroke="url(#bone)" strokeWidth={sw} strokeLinecap="round" fill="none"/>
            </>
          ) : (
            <>
              {/* floating rib — from spine */}
              <path d={`M212 ${290+i*8-40} Q180 ${290+i*8-35} ${lx} ${ly}`}
                stroke="#db261d" strokeWidth={sw+0.8} strokeLinecap="round" fill="none" filter="url(#g1)"/>
              <path d={`M212 ${290+i*8-40} Q180 ${290+i*8-35} ${lx} ${ly}`}
                stroke="url(#bone)" strokeWidth={sw} strokeLinecap="round" fill="none"/>
            </>
          )}
          {/* costal cartilage (dashed) */}
          {costal && (
            <path d={`M${lx} ${ly} Q${lx+20} ${ly+6} 212 ${285}`}
              stroke="rgba(219,38,29,0.38)" strokeWidth="2" strokeDasharray="5 4" strokeLinecap="round" fill="none"/>
          )}
          {/* Right rib */}
          {sy > 0 ? (
            <>
              <path d={`M247 ${sy} Q${rcpx} ${rcpy} ${rx2} ${ry2}`}
                stroke="#db261d" strokeWidth={sw+1} strokeLinecap="round" fill="none" filter="url(#g1)"/>
              <path d={`M247 ${sy} Q${rcpx} ${rcpy} ${rx2} ${ry2}`}
                stroke="url(#bone)" strokeWidth={sw} strokeLinecap="round" fill="none"/>
            </>
          ) : (
            <>
              <path d={`M248 ${290+i*8-40} Q280 ${290+i*8-35} ${rx2} ${ry2}`}
                stroke="#db261d" strokeWidth={sw+0.8} strokeLinecap="round" fill="none" filter="url(#g1)"/>
              <path d={`M248 ${290+i*8-40} Q280 ${290+i*8-35} ${rx2} ${ry2}`}
                stroke="url(#bone)" strokeWidth={sw} strokeLinecap="round" fill="none"/>
            </>
          )}
          {costal && (
            <path d={`M${rx2} ${ry2} Q${rx2-20} ${ry2+6} 248 ${285}`}
              stroke="rgba(219,38,29,0.38)" strokeWidth="2" strokeDasharray="5 4" strokeLinecap="round" fill="none"/>
          )}
        </g>
      );
    })}

    {/* ═══════════════════════════════════════
        THORACIC VERTEBRAE  T1–T12
    ═══════════════════════════════════════ */}
    {Array.from({length:12}).map((_,i)=>{
      const y = 200 + i*11;
      return (
        <g key={i}>
          <rect x="219" y={y-5} width="22" height="9" rx="2.5"
            fill="url(#bone)" stroke="#db261d" strokeWidth="0.9" filter="url(#g1)"/>
          <ellipse cx="230" cy={y-10} rx="5.5" ry="4.5"
            fill="url(#boneFlat)" stroke="#db261d" strokeWidth="0.7"/>
        </g>
      );
    })}

    {/* ═══════════════════════════════════════
        LUMBAR VERTEBRAE  L1–L5
    ═══════════════════════════════════════ */}
    {Array.from({length:5}).map((_,i)=>{
      const y = 336 + i*17;
      return (
        <g key={i}>
          <rect x="213" y={y-7} width="34" height="13" rx="4"
            fill="url(#bone)" stroke="#db261d" strokeWidth="1.2" filter="url(#g1)"/>
          <rect x="213" y={y-7} width="34" height="13" rx="4" fill="url(#boneShine)"/>
          <path d={`M213 ${y} Q200 ${y-4} 193 ${y}`} fill="none" stroke="#db261d" strokeWidth="4" strokeLinecap="round" filter="url(#g1)"/>
          <path d={`M213 ${y} Q200 ${y-4} 193 ${y}`} fill="none" stroke="url(#bone)" strokeWidth="3" strokeLinecap="round"/>
          <path d={`M247 ${y} Q260 ${y-4} 267 ${y}`} fill="none" stroke="#db261d" strokeWidth="4" strokeLinecap="round" filter="url(#g1)"/>
          <path d={`M247 ${y} Q260 ${y-4} 267 ${y}`} fill="none" stroke="url(#bone)" strokeWidth="3" strokeLinecap="round"/>
          <rect x="224" y={y-17} width="12" height="11" rx="3" fill="url(#boneFlat)" stroke="#db261d" strokeWidth="0.8"/>
        </g>
      );
    })}

    {/* ═══════════════════════════════════════
        PELVIS
    ═══════════════════════════════════════ */}
    {/* Sacrum */}
    <path d="M213 421 Q230 416 247 421 L252 510 Q230 518 208 510 Z"
      fill="url(#bone)" stroke="#db261d" strokeWidth="1.4" filter="url(#g1)"/>
    <path d="M213 421 Q230 416 247 421 L252 510 Q230 518 208 510 Z" fill="url(#boneShine)"/>
    {/* Sacral foramina */}
    {[436,452,468,484].map((y,i)=>(
      <g key={i}>
        <ellipse cx="223" cy={y} rx="4.5" ry="3.5" fill="url(#cavity)" stroke="rgba(219,38,29,0.4)" strokeWidth="0.7"/>
        <ellipse cx="237" cy={y} rx="4.5" ry="3.5" fill="url(#cavity)" stroke="rgba(219,38,29,0.4)" strokeWidth="0.7"/>
      </g>
    ))}
    {/* Coccyx */}
    <path d="M220 510 Q230 515 240 510 L237 538 L230 545 L223 538 Z"
      fill="url(#boneFlat)" stroke="#db261d" strokeWidth="1.1" filter="url(#g1)"/>
    {/* Left ilium wing */}
    <path d="M208 421 Q188 416 168 408 Q148 400 140 420 Q134 438 145 456 Q158 472 180 476 L190 508 L208 510 Z"
      fill="url(#bone)" stroke="#db261d" strokeWidth="1.4" filter="url(#g1)"/>
    <path d="M208 421 Q188 416 168 408 Q148 400 140 420 Q134 438 145 456 Q158 472 180 476 L190 508 L208 510 Z"
      fill="url(#boneShine)"/>
    {/* Right ilium wing */}
    <path d="M252 421 Q272 416 292 408 Q312 400 320 420 Q326 438 315 456 Q302 472 280 476 L270 508 L252 510 Z"
      fill="url(#bone)" stroke="#db261d" strokeWidth="1.4" filter="url(#g1)"/>
    <path d="M252 421 Q272 416 292 408 Q312 400 320 420 Q326 438 315 456 Q302 472 280 476 L270 508 L252 510 Z"
      fill="url(#boneShine)"/>
    {/* Iliac crest lines */}
    <path d="M208 421 Q188 408 168 408 Q148 406 140 420" fill="none" stroke="rgba(219,38,29,0.4)" strokeWidth="1.2" strokeDasharray="4 3"/>
    <path d="M252 421 Q272 408 292 408 Q312 406 320 420" fill="none" stroke="rgba(219,38,29,0.4)" strokeWidth="1.2" strokeDasharray="4 3"/>
    {/* Acetabulum (hip socket) */}
    <circle cx="168" cy="492" r="22" fill="rgba(30,0,0,0.7)" stroke="#db261d" strokeWidth="1.8" filter="url(#g1)"/>
    <circle cx="168" cy="492" r="14" fill="rgba(60,5,5,0.6)" stroke="rgba(219,38,29,0.5)" strokeWidth="1"/>
    <circle cx="292" cy="492" r="22" fill="rgba(30,0,0,0.7)" stroke="#db261d" strokeWidth="1.8" filter="url(#g1)"/>
    <circle cx="292" cy="492" r="14" fill="rgba(60,5,5,0.6)" stroke="rgba(219,38,29,0.5)" strokeWidth="1"/>
    {/* Pubic symphysis */}
