/* ─────────────────────────────────────────
   INTERACTIVE WRAPPER
───────────────────────────────────────── */
const SkeletonBody = () => {
  const ref = useRef(null);
  const [mouse, setMouse] = useState({ x:0, y:0 });
  const [hovered, setHovered] = useState(null);
  const scanRef = useRef(0);
  const [scanY, setScanY] = useState(0);
  const dirRef = useRef(1);
  const rafRef = useRef(null);

  const onMove = useCallback((e) => {
    if (!ref.current) return;
    const r = ref.current.getBoundingClientRect();
    setMouse({
      x: ((e.clientX - r.left) / r.width  - 0.5) * 2,
      y: ((e.clientY - r.top)  / r.height - 0.5) * 2,
    });
  }, []);

  useEffect(() => {
    const tick = () => {
      scanRef.current += dirRef.current * 1.5;
      if (scanRef.current > 840) dirRef.current = -1;
      if (scanRef.current <   0) dirRef.current =  1;
      setScanY(scanRef.current);
      rafRef.current = requestAnimationFrame(tick);
    };
    rafRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(rafRef.current);
  }, []);

  const rx = mouse.y * -5;
  const ry = mouse.x *  7;
  const tx = mouse.x * 10;
  const ty = mouse.y *  5;

  return (
    <div ref={ref} onMouseMove={onMove}
      onMouseLeave={() => { setMouse({x:0,y:0}); setHovered(null); }}
      style={{ position:'relative', width:'380px', height:'660px', cursor:'crosshair', perspective:'1100px' }}>

      <style>{`
        @keyframes bodyFloat { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-8px)} }
        @keyframes ambGlow   { 0%,100%{opacity:.5} 50%{opacity:.95} }
      `}</style>

      {/* ambient radial glow */}
      <div style={{
        position:'absolute', inset:'-40px',
        background:'radial-gradient(ellipse at 50% 45%, rgba(219,38,29,0.12) 0%, transparent 62%)',
        pointerEvents:'none', animation:'ambGlow 4s ease-in-out infinite',
      }}/>

      {/* 3-D tilt + float */}
      <div style={{
        transform:`rotateX(${rx}deg) rotateY(${ry}deg) translate(${tx}px,${ty}px)`,
        transition:'transform 0.1s ease-out',
        transformStyle:'preserve-3d',
        animation:'bodyFloat 5.5s ease-in-out infinite',
      }}>
        <SkeletonSVG scanY={scanY} hovered={hovered} setHovered={setHovered}/>
      </div>

      {/* ── HOVER TOOLTIP ── */}
      {hovered && (() => {
        const p = HOTSPOTS.find(x => x.id === hovered);
        const goRight = p.cx < 230;
        return (
          <div style={{
            position:'absolute',
            top:`${(p.cy/820)*100}%`,
            [goRight?'right':'left']:'4px',
            transform:'translateY(-50%)',
            background:'rgba(8,0,0,0.95)',
            border:'1px solid rgba(219,38,29,0.85)',
            borderRadius:'10px', padding:'8px 14px',
            pointerEvents:'none', backdropFilter:'blur(12px)',
            boxShadow:'0 0 24px rgba(219,38,29,0.45)',
            zIndex:30, whiteSpace:'nowrap',
          }}>
            <div style={{color:'#ffdd44', fontSize:'11px', fontWeight:800}}>● {p.label}</div>
            <div style={{color:'rgba(255,190,155,0.85)', fontSize:'10px', marginTop:'3px'}}>{p.sub}</div>
          </div>
        );
      })()}

      {/* ── ALWAYS-ON LABELS ── */}
      {HOTSPOTS.map((p) => {
        const goRight = p.cx < 230;
        const h = hovered === p.id;
        return (
          <div key={p.id} style={{
            position:'absolute',
            top:`${(p.cy/820)*100}%`,
            [goRight?'right':'left']:'2px',
            transform:'translateY(-50%)',
            background:h?'rgba(20,0,0,0.97)':'rgba(8,0,0,0.84)',
            border:`1px solid rgba(219,38,29,${h?.92:.42})`,
            borderRadius:'8px', padding:'4px 10px',
            pointerEvents:'none', backdropFilter:'blur(8px)',
            boxShadow:h?'0 0 20px rgba(219,38,29,0.55)':'none',
            transition:'all .3s', zIndex:h?0:5, whiteSpace:'nowrap',
            display:h?'none':'block',
          }}>
            <div style={{color:'#ff9966', fontSize:'10px', fontWeight:700}}>● {p.label}</div>
          </div>
        );
      })}
    </div>
  );
};

